   210→    document.addEventListener('DOMContentLoaded', async () => {
   211→      const user = await checkAuth();
   212→      if (!user) {
   213→        window.location.href = '/login.html';
   214→        return;
   215→      }
   216→
   217→      // Update greeting
   218→      const name = user.name || user.email.split('@')[0];
   219→      document.getElementById('greeting-name').textContent = name;
   220→      document.getElementById('user-name').textContent = name;
   221→      document.getElementById('user-avatar').textContent = name.charAt(0).toUpperCase();
   222→
   223→      if (user.is_paid) {
   224→        document.getElementById('user-plan').textContent = 'Pro Plan';
   225→        document.getElementById('user-plan').classList.add('pro');
   226→        document.getElementById('upgrade-banner').style.display = 'none';
   227→      }
   228→
   229→      loadDashboard();
   230→    });
   231→
   232→    async function loadDashboard() {
   233→      try {
   234→        // Load dashboard stats
   235→        const stats = await apiCall('/candidate/dashboard/stats');
   236→        if (stats.success) {
   237→          dashboardData = stats.stats;
   238→          renderStats(stats.stats);
   239→        }
   240→
   241→        // Load skills
   242→        const skills = await apiCall('/candidate/skills');
   243→        if (skills.success) {
   244→          renderSkillsPreview(skills.skills);
   245→        }
   246→
   247→        // Load recent activity
   248→        loadRecentActivity();
   249→
   250→      } catch (err) {
   251→        console.error('Dashboard load error:', err);
   252→      }
   253→    }
   254→
   255→    function renderStats(stats) {
   256→      // Profile completeness
   257→      const completeness = stats.profile_completeness || 0;
   258→      document.getElementById('completeness-value').textContent = completeness + '%';
   259→      document.getElementById('completeness-path').setAttribute('stroke-dasharray', `${completeness}, 100`);
   260→
   261→      if (completeness >= 80) {
   262→        document.getElementById('completeness-message').textContent = 'Your profile is looking great!';
   263→      } else if (completeness >= 50) {
   264→        document.getElementById('completeness-message').textContent = 'Almost there! Add more details.';
   265→      }
   266→
   267→      // OmniScore
   268→      if (stats.omniscore) {
   269→        document.getElementById('omniscore-value').textContent = stats.omniscore.total_score;
   270→        document.getElementById('omniscore-tier').textContent = stats.omniscore.tier_label;
   271→        document.getElementById('omniscore-tier').className = 'omniscore-badge ' + (stats.omniscore.tier || '').replace('_', '-');
   272→      }
   273→
   274→      // Stats cards
   275→      document.getElementById('skills-count').textContent = stats.skills?.total || 0;
   276→      document.getElementById('verified-skills').textContent = stats.skills?.verified || 0;
   277→      document.getElementById('interview-count').textContent = stats.interviews?.total || 0;
   278→      document.getElementById('applications-count').textContent = stats.applications || 0;
   279→    }
   280→
   281→    function renderSkillsPreview(skills) {
   282→      const container = document.getElementById('skills-preview');
   283→
   284→      if (!skills || skills.length === 0) {
   285→        container.innerHTML = `
   286→          <div class="empty-skills">
   287→            <p>No skills added yet</p>
   288→            <a href="/candidate-profile.html#skills" class="btn btn-primary btn-sm">Add Your Skills</a>
   289→          </div>
   290→        `;
   291→        return;
   292→      }
   293→
   294→      // Group by category
   295→      const categories = {};
   296→      skills.forEach(s => {
   297→        const cat = s.category || 'technical';
   298→        if (!categories[cat]) categories[cat] = [];
   299→        categories[cat].push(s);
   300→      });
   301→
   302→      container.innerHTML = Object.entries(categories).map(([cat, catSkills]) => `
   303→        <div class="skill-category">
   304→          <h4>${formatCategory(cat)}</h4>
   305→          <div class="skill-tags">
   306→            ${catSkills.slice(0, 8).map(s => `
   307→              <span class="skill-tag ${s.is_verified ? 'verified' : ''}" title="Level ${s.level}/5">
   308→                ${s.skill_name}
   309→                ${s.is_verified ? '<span class="verified-badge">✓</span>' : ''}
   310→                <span class="skill-level">${'●'.repeat(s.level)}${'○'.repeat(5-s.level)}</span>
   311→              </span>
   312→            `).join('')}
   313→            ${catSkills.length > 8 ? `<span class="more-skills">+${catSkills.length - 8} more</span>` : ''}
   314→          </div>
   315→        </div>
   316→      `).join('');
   317→    }
   318→
   319→    function formatCategory(cat) {
   320→      const labels = {
   321→        'technical': '💻 Technical',
   322→        'soft_skill': '🤝 Soft Skills',
   323→        'tool': '🔧 Tools',
   324→        'language': '🌍 Languages'
   325→      };
   326→      return labels[cat] || cat;
   327→    }
   328→
   329→    async function loadRecentActivity() {
   330→      const container = document.getElementById('activity-list');
   331→
   332→      try {
   333→        // Load recent interviews
   334→        const interviews = await apiCall('/interviews?limit=3');
   335→        // Load recent applications
   336→        const applications = await apiCall('/candidate/applications');
   337→
   338→        const activities = [];
   339→
   340→        if (interviews.interviews) {
   341→          interviews.interviews.slice(0, 3).forEach(i => {
   342→            activities.push({
   343→              type: 'interview',
   344→              title: 'Mock Interview',
   345→              subtitle: i.interview_type || 'General',
   346→              score: i.overall_score,
   347→              date: i.created_at
   348→            });
   349→          });
   350→        }
   351→
   352→        if (applications.applications) {
   353→          applications.applications.slice(0, 3).forEach(a => {
   354→            activities.push({
   355→              type: 'application',
   356→              title: `Applied to ${a.title}`,
   357→              subtitle: a.company || 'Unknown Company',
   358→              status: a.status,
   359→              date: a.applied_at
   360→            });
   361→          });
   362→        }
   363→
   364→        // Sort by date
   365→        activities.sort((a, b) => new Date(b.date) - new Date(a.date));
   366→
   367→        if (activities.length === 0) {
   368→          container.innerHTML = `
   369→            <div class="empty-state">
   370→              <p>No recent activity. Start by taking a mock interview!</p>
   371→              <a href="/interview.html" class="btn btn-primary btn-sm">Start Interview</a>
   372→            </div>
   373→          `;
   374→          return;
   375→        }
   376→
   377→        container.innerHTML = `
   378→          <div class="activity-items">
   379→            ${activities.slice(0, 5).map(a => `
   380→              <div class="activity-item">
   381→                <div class="activity-icon ${a.type}">${a.type === 'interview' ? '🎤' : '📄'}</div>
   382→                <div class="activity-details">
   383→                  <span class="activity-title">${a.title}</span>
   384→                  <span class="activity-subtitle">${a.subtitle}</span>
   385→                </div>
   386→                <div class="activity-meta">
   387→                  ${a.score ? `<span class="activity-score">${a.score}/10</span>` : ''}
   388→                  ${a.status ? `<span class="activity-status ${a.status}">${a.status}</span>` : ''}
   389→                  <span class="activity-date">${formatDate(a.date)}</span>
   390→                </div>
   391→              </div>
   392→            `).join('')}
   393→          </div>
   394→        `;
   395→      } catch (err) {
   396→        container.innerHTML = `<div class="empty-state"><p>Could not load activity</p></div>`;
   397→      }
   398→    }
   399→
   400→    function formatDate(dateStr) {
   401→      const date = new Date(dateStr);
   402→      const now = new Date();
   403→      const diff = now - date;
   404→      const days = Math.floor(diff / (1000 * 60 * 60 * 24));
   405→
   406→      if (days === 0) return 'Today';
   407→      if (days === 1) return 'Yesterday';
   408→      if (days < 7) return `${days} days ago`;
   409→      return date.toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
   410→    }
