   185→  <script>
   186→    // Check recruiter auth
   187→    document.addEventListener('DOMContentLoaded', async () => {
   188→      const user = await checkAuth();
   189→      if (!user) {
   190→        window.location.href = '/login.html';
   191→        return;
   192→      }
   193→
   194→      // Verify recruiter role
   195→      if (!user.company_id && user.role !== 'recruiter') {
   196→        window.location.href = '/dashboard.html';
   197→        return;
   198→      }
   199→
   200→      // Update user info
   201→      const name = user.name || user.email.split('@')[0];
   202→      document.getElementById('user-name').textContent = name;
   203→      document.getElementById('user-avatar').textContent = name.charAt(0).toUpperCase();
   204→      document.getElementById('company-name').textContent = user.company_name || 'Company';
   205→
   206→      // Load dashboard data
   207→      loadRecruiterDashboard();
   208→    });
   209→
   210→    async function loadRecruiterDashboard() {
   211→      try {
   212→        const data = await apiCall('/recruiter/dashboard');
   213→        if (!data) return;
   214→
   215→        // Update TrustScore
   216→        if (data.trust_score) {
   217→          document.getElementById('trustscore-value').textContent = data.trust_score.total_score;
   218→          document.getElementById('trustscore-tier').textContent = data.trust_score.tier_label;
   219→          document.getElementById('trustscore-tier').style.background = data.trust_score.tier_color;
   220→        }
   221→
   222→        // Update stats
   223→        document.getElementById('active-jobs').textContent = data.job_stats?.active_jobs || 0;
   224→        document.getElementById('total-applications').textContent = data.application_stats?.total_applications || 0;
   225→        document.getElementById('new-applications').textContent = data.application_stats?.new_applications || 0;
   226→
   227→        const interviewed = parseInt(data.application_stats?.interviewed) || 0;
   228→        const offered = parseInt(data.application_stats?.offered) || 0;
   229→        const ratio = interviewed > 0 ? ((offered / interviewed) * 100).toFixed(0) + '%' : '-';
   230→        document.getElementById('offer-ratio').textContent = ratio;
   231→
   232→        // Render upcoming interviews
   233→        renderUpcomingInterviews(data.upcoming_interviews || []);
   234→
   235→        // Render recent applications
   236→        renderRecentApplications(data.recent_applications || []);
   237→
   238→      } catch (err) {
   239→        console.error('Failed to load dashboard:', err);
   240→      }
   241→    }
   242→
   243→    function renderUpcomingInterviews(interviews) {
   244→      const container = document.getElementById('upcoming-interviews');
   245→
   246→      if (interviews.length === 0) {
   247→        container.innerHTML = `
   248→          <div class="empty-state">
   249→            <p>No upcoming interviews</p>
   250→            <a href="/recruiter-applications.html" class="btn btn-ghost btn-sm">Review applications</a>
   251→          </div>
   252→        `;
   253→        return;
   254→      }
   255→
   256→      container.innerHTML = interviews.map(i => `
   257→        <div class="interview-item">
   258→          <div class="interview-time">
   259→            <span class="date">${new Date(i.scheduled_at).toLocaleDateString()}</span>
   260→            <span class="time">${new Date(i.scheduled_at).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</span>
   261→          </div>
   262→          <div class="interview-info">
   263→            <span class="candidate-name">${i.candidate_name}</span>
   264→            <span class="job-title">${i.job_title}</span>
   265→          </div>
   266→          <span class="interview-type-badge ${i.interview_type}">${i.interview_type}</span>
   267→        </div>
   268→      `).join('');
   269→    }
   270→
   271→    function renderRecentApplications(applications) {
   272→      const container = document.getElementById('recent-applications');
   273→
   274→      if (applications.length === 0) {
   275→        container.innerHTML = `
   276→          <div class="empty-state">
   277→            <p>No applications yet</p>
   278→            <a href="/job-create.html" class="btn btn-ghost btn-sm">Post a job</a>
   279→          </div>
   280→        `;
   281→        return;
   282→      }
   283→
   284→      container.innerHTML = applications.map(a => `
   285→        <div class="application-item">
   286→          <div class="candidate-info">
   287→            <span class="candidate-name">${a.candidate_name}</span>
   288→            <span class="job-title">${a.job_title}</span>
   289→          </div>
   290→          <div class="application-meta">
   291→            ${a.omniscore_at_apply ? `<span class="omniscore-badge">${a.omniscore_at_apply} OmniScore</span>` : ''}
   292→            <span class="status-badge ${a.status}">${a.status}</span>
   293→          </div>
   294→        </div>
   295→      `).join('');
   296→    }
