// Check recruiter auth
document.addEventListener('DOMContentLoaded', async () => {
  const user = await checkAuth();
  if (!user) {
    window.location.href = '/login.html';
    return;
  }

  // Verify recruiter role
  if (!user.company_id && user.role !== 'recruiter') {
    window.location.href = '/dashboard.html';
    return;
  }

  // Update user info
  const name = user.name || user.email.split('@')[0];
  document.getElementById('user-name').textContent = name;
  document.getElementById('user-avatar').textContent = name.charAt(0).toUpperCase();
  document.getElementById('company-name').textContent = user.company_name || 'Company';
  document.getElementById('dropdown-user-name').textContent = name;
  document.getElementById('dropdown-user-email').textContent = user.email;

  // Setup user menu dropdown
  const userMenuToggle = document.getElementById('user-menu-toggle');
  const userDropdownMenu = document.getElementById('user-dropdown-menu');
  if (userMenuToggle && userDropdownMenu) {
    userMenuToggle.addEventListener('click', (e) => {
      e.stopPropagation();
      userDropdownMenu.classList.toggle('active');
    });

    document.addEventListener('click', () => {
      userDropdownMenu.classList.remove('active');
    });

    userDropdownMenu.addEventListener('click', (e) => {
      e.stopPropagation();
    });
  }

  // Load dashboard data
  loadRecruiterDashboard();
});

