  const user = await checkAuth();
  if (!user || !user.company_id) {
    window.location.href = '/login.html';
    return;
  }

  const name = user.name || user.email.split('@')[0];
  document.getElementById('user-name').textContent = name;
  document.getElementById('user-avatar').textContent = name.charAt(0).toUpperCase();
  document.getElementById('company-name').textContent = user.company_name || 'Company';

  loadCompanyProfile();
});

async function loadCompanyProfile() {
  try {
    const data = await apiCall('/company/profile');
    if (!data) return;

    companyData = data.company;
    populateForm(companyData);
    updateCompleteness(companyData);
    updateVerificationStatus(companyData);
  } catch (err) {
    console.error('Failed to load profile:', err);
  }
}

